('C2', 1112, $$Idioms de negócios$$, $$ballpark figure, touch base$$, $$💼$$,
$$O inglês corporativo é cheio de expressões idiomáticas. Reconhecê-las é essencial em reuniões internacionais.$$,
$$"Touch base" = dar um alô / alinhar rapidamente. "Ballpark figure" = valor aproximado.$$,
$j$[{"en":"Let us touch base next week.","pt":"Vamos nos alinhar na próxima semana."},{"en":"Can you give me a ballpark figure?","pt":"Pode me dar um valor aproximado?"},{"en":"We need to think outside the box.","pt":"Precisamos pensar de forma criativa."}]$j$::jsonb,
$j$[{"q":"'Touch base' significa:","ctx":"","opts":["alinhar/dar um alô","tocar a base","começar do zero","assinar contrato"],"ans":0,"exp":"Contato rápido."},{"q":"'Ballpark figure' =","ctx":"","opts":["valor aproximado","número exato","lucro final","meta anual"],"ans":0,"exp":"Estimativa."},{"q":"'To be on the same page' =","ctx":"","opts":["estar de acordo","ler o mesmo livro","na mesma sala","no mesmo nível"],"ans":0,"exp":"Mesmo entendimento."},{"q":"'The bottom line' =","ctx":"","opts":["o ponto principal","a última linha","o rodapé","o prejuízo"],"ans":0,"exp":"O que importa."},{"q":"'To get the ball rolling' =","ctx":"","opts":["dar início","encerrar","atrasar","cancelar"],"ans":0,"exp":"Começar."},{"q":"'A win-win situation' =","ctx":"","opts":["bom para os dois lados","vitória difícil","sem solução","jogo duplo"],"ans":0,"exp":"Todos ganham."}]$j$::jsonb),

('C2', 1113, $$Intensificadores e atenuadores$$, $$utterly, fairly, somewhat$$, $$📈$$,
$$Advérbios de grau ajustam a força de um adjetivo: utterly/absolutely (muito forte), fairly/somewhat (moderado), slightly (leve).$$,
$$"Utterly" e "absolutely" combinam com adjetivos extremos: "absolutely exhausted", não "absolutely tired".$$,
$j$[{"en":"The film was utterly brilliant.","pt":"O filme foi absolutamente brilhante."},{"en":"I am somewhat tired today.","pt":"Estou um tanto cansado hoje."},{"en":"It is fairly common here.","pt":"É bastante comum por aqui."}]$j$::jsonb,
$j$[{"q":"'Utterly' indica grau:","ctx":"","opts":["muito forte","leve","médio","nenhum"],"ans":0,"exp":"Intensificador forte."},{"q":"'Somewhat' significa:","ctx":"","opts":["um tanto","totalmente","jamais","extremamente"],"ans":0,"exp":"Moderado."},{"q":"Combina com 'exhausted':","ctx":"","opts":["absolutely","very","fairly","a bit"],"ans":0,"exp":"Adjetivo extremo + absolutely."},{"q":"'Slightly' =","ctx":"","opts":["levemente","muito","sempre","nunca"],"ans":0,"exp":"Grau leve."},{"q":"Atenuador (suaviza):","ctx":"","opts":["rather","utterly","absolutely","completely"],"ans":0,"exp":"'Rather' modera."},{"q":"'Quite' diante de extremo soa:","ctx":"","opts":["estranho (use absolutely)","perfeito","formal","grosseiro"],"ans":0,"exp":"Extremos pedem absolutely."}]$j$::jsonb),

('C2', 1114, $$Linguagem de manchetes$$, $$headlines: PM vows, talks set$$, $$📰$$,
$$Manchetes de jornal usam gramática própria: omitem artigos, usam presente para o passado e infinitivo para o futuro.$$,
