('C2', 1115, $$Expressões latinas no inglês$$, $$per se, vice versa, etc.$$, $$🏛️$$,
$$O inglês formal e acadêmico usa termos latinos: per se (em si), vice versa, etc. (e assim por diante), i.e. (isto é), e.g. (por exemplo).$$,
$$"i.e." esclarece (isto é); "e.g." dá exemplos (por exemplo). Não confunda os dois.$$,
$j$[{"en":"The plan is not bad per se.","pt":"O plano não é ruim em si."},{"en":"She helps him and vice versa.","pt":"Ela o ajuda e vice-versa."},{"en":"Bring fruit, e.g. apples.","pt":"Traga frutas, por exemplo maçãs."}]$j$::jsonb,
$j$[{"q":"'per se' significa:","ctx":"","opts":["em si mesmo","por favor","com certeza","de novo"],"ans":0,"exp":"Em si."},{"q":"'i.e.' =","ctx":"","opts":["isto é","por exemplo","e outros","ou seja não"],"ans":0,"exp":"id est = isto é."},{"q":"'e.g.' =","ctx":"","opts":["por exemplo","isto é","e assim por diante","sem dúvida"],"ans":0,"exp":"exempli gratia."},{"q":"'etc.' =","ctx":"","opts":["e assim por diante","isto é","por exemplo","com licença"],"ans":0,"exp":"et cetera."},{"q":"'vice versa' =","ctx":"","opts":["o contrário também","duas vezes","ao contrário errado","em vão"],"ans":0,"exp":"Reciprocamente."},{"q":"'ad hoc' =","ctx":"","opts":["feito para um fim específico","muito antigo","de graça","ilegal"],"ans":0,"exp":"Para um propósito."}]$j$::jsonb),

('C2', 1116, $$Phrasal verbs de três partes$$, $$look forward to, put up with$$, $$🔧$$,
$$Phrasal verbs de três partes (verbo + advérbio + preposição) nunca se separam e têm sentido idiomático.$$,
$$"Look forward to" é seguido de substantivo ou verbo -ing: "I look forward to seeing you."$$,
$j$[{"en":"I look forward to your reply.","pt":"Aguardo ansiosamente sua resposta."},{"en":"She came up with a plan.","pt":"Ela bolou um plano."},{"en":"We ran out of time.","pt":"Ficamos sem tempo."}]$j$::jsonb,
