$j$[{"en":"I am gonna call you later.","pt":"Vou te ligar mais tarde."},{"en":"Do you wanna come?","pt":"Você quer vir?"},{"en":"It is kinda cold.","pt":"Está meio frio."}]$j$::jsonb,
