('C2', 1118, $$Marcadores de coesão textual$$, $$moreover, nevertheless, thereby$$, $$🔗$$,
$$Conectores formais dão fluidez a textos avançados: moreover (além disso), nevertheless (ainda assim), thus/thereby (assim), whereas (ao passo que).$$,
$$"Nevertheless" admite um contraste apesar do que foi dito; "moreover" acrescenta um argumento.$$,
$j$[{"en":"The data is old; moreover, it is incomplete.","pt":"Os dados são antigos; além disso, incompletos."},{"en":"It rained; nevertheless, we went.","pt":"Choveu; ainda assim, fomos."},{"en":"He saved money, whereas she spent.","pt":"Ele economizou, ao passo que ela gastou."}]$j$::jsonb,
$j$[{"q":"'moreover' =","ctx":"","opts":["além disso","no entanto","portanto","por exemplo"],"ans":0,"exp":"Adiciona."},{"q":"'nevertheless' =","ctx":"","opts":["ainda assim","além disso","assim","porque"],"ans":0,"exp":"Contraste."},{"q":"'whereas' =","ctx":"","opts":["ao passo que","porque","então","embora não"],"ans":0,"exp":"Contraste paralelo."},{"q":"'thus' =","ctx":"","opts":["assim/portanto","além disso","mas","quando"],"ans":0,"exp":"Consequência."},{"q":"'in contrast' indica:","ctx":"","opts":["oposição","adição","causa","tempo"],"ans":0,"exp":"Contraste."},{"q":"Esses marcadores são típicos de:","ctx":"","opts":["texto formal/acadêmico","conversa casual","gírias","manchetes"],"ans":0,"exp":"Registro formal."}]$j$::jsonb),

('C2', 1119, $$Linguagem inclusiva e neutra$$, $$they, chairperson, staff$$, $$🤝$$,
